def _interpolate(self, value, line_num, filename):
    """Replace ${var} references with variable values."""
    def replacer(match):
        var_name = match.group(1)
        if var_name in self.variables:
            return self.variables[var_name]
        if self.strict:
            raise ParseError(
                f"Undefined variable '${{{var_name}}}'",
                line_num, filename
            )
        return ""

    return re.sub(r'\$\{(\w+)\}', replacer, value)

def get_undefined_references(self, text) -> list:
    """Return variable names referenced but not defined, without raising errors."""
    defined = set(self.variables.keys())
    undefined = []
    seen = set()

    for line in text.splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith('#'):
            continue
        if stripped.startswith('$'):
            match = re.match(r'\$(\w+)\s*=\s*(.*)', stripped)
            if match:
                defined.add(match.group(1))
                continue
        for match in re.finditer(r'\$\{(\w+)\}', stripped):
            var_name = match.group(1)
            if var_name not in defined and var_name not in seen:
                undefined.append(var_name)
                seen.add(var_name)

    return undefined
